sql:
SELECT feature, coverage_method
FROM verification_requirements
WHERE feature LIKE '%RV32I%';

SELECT coverage_value
FROM coverage_analysis
WHERE requirement_id = 2;

SELECT COUNT(*) 
FROM coverage_analysis
WHERE coverage_method = 'Functional coverage of rs1 and imm';

SELECT coverage_method, AVG(cast(coverage_value as REAL)) AS average_coverage
FROM coverage_analysis
GROUP BY coverage_method;

SELECT requirement_id, feature, sub_feature
FROM verification_requirements
ORDER BY requirement_id;

SELECT COUNT(*) AS successful_executions
FROM test_case_execution_history
WHERE execution_status = 'Success' AND execution_date BETWEEN '2022-01-01' AND '2022-01-31';

SELECT created_by, COUNT(requirement_id) AS number_of_requirements
FROM verification_requirements
GROUP BY created_by;

SELECT COUNT(DISTINCT test_case_id) AS failed_test_cases_count
FROM test_case_execution_history
WHERE execution_status = 'Failure';

SELECT feature, sub_feature, description, verification_goal, pass_fail_criteria, coverage_method
FROM verification_requirements
WHERE requirement_id = 1;

external_knowledge:
; The pass rate is calculated as the percentage of test cases that passed for each feature;
; It is assumed that the pass or fail status of a test case is represented by 'Pass' for passed tests and any other value for failed tests;
; The query only considers features with at least one test result, implying that untested features are not included in the results.
